var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"으윽…… 집이 뭐가 이렇게 높아?","JPN":"ううっ……なんと高い家なんじゃ？","ENG":"Ugh... Why is your place located so high?","TWN":"呃……哪有人家住這麼高的？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나오님, 괜찮으신가요? 아까부터 안색이 좋지 않으십니다만.","JPN":"ナオ様、大丈夫ですか？　さっきから顔色がよくありませんが。","ENG":"Are you okay, Miss Nao? You do not look so well.","TWN":"奈緒，你還好嗎？你從剛才就臉色不太好？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"사람이라면…… 자고로 땅을 밟고 살아야 하는 것을-","JPN":"人間たるもの……土を踏んで生きるべし……","ENG":"Humans belong on land, not in air...","TWN":"自古以來……人就是要在這塊土地上掘地而居-"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이런 마천루에 터를 잡고 지내다니…… 가문연합의 위세도 갈 때까지 갔구나.","JPN":"こんな摩天楼に住みつくとは……連合の威勢も廃れたもんじゃのう。","ENG":"To set this pagoda of a place as your dwelling... it looks like the Alliance has become more than arrogant.","TWN":"竟然在這種摩天大樓定居……難怪家族聯盟會沒落。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네? 저희 가문연합에 대해 알고 계셨나요?","JPN":"はい？　連合についてご存じでしたか？","ENG":"Huh? Have you heard of us before?","TWN":"什麼？你認識我們家族聯盟嗎？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"흥…… 알다마다. 가문연합에서 내가 거둬 키운 제자들만 몇 놈인데.","JPN":"ふん……当たり前じゃ。わしが連合から引き取って育てた弟子がたくさんおる。","ENG":"Hmph... Of course I have. I have accepted more than enough apprentices from you all.","TWN":"哼……當然認識，裡面有幾個是我收的徒弟呢。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제자……?","JPN":"弟子……？","ENG":"Apprentice...?","TWN":"徒弟……？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"으으윽……!","JPN":"うううっ……！","ENG":"Ughhh...!","TWN":"呃呃呃……！"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나, 나오님?","JPN":"な、ナオ様？","ENG":"M-miss Nao?","TWN":"奈…奈緒？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"설마……?! 좀 전의 상처에 독 같은 것이……?","JPN":"まさか……！？　先ほどの傷に毒のようなものが……？","ENG":"Oh, no...! Could it be some sort of poison from the wound...?","TWN":"難道……？！是因為剛才傷口上的毒……？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"아니……","JPN":"いや……","ENG":"No...","TWN":"不是……"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"투명한 엘리베이터 때문에…… 속이 안 좋아.","JPN":"透明なエレベーターのせいで……酔った。","ENG":"Your glass elevator... It’s making me nauseous.","TWN":"都是這個透明電梯害的……我想吐。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"什麼？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님께서 독에 당한 손님이 있다고 하셔서 왔습니다만……","JPN":"ご当主様から毒にやられたお客様がいると聞き、やってまいりましたが……","ENG":"I heard that there was a guest who has been poisoned...","TWN":"堂主說有位中毒的客人，需要我來……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"밥맛이 좋구나~ 한 그릇 더~","JPN":"ウマいのう～おかわり～","ENG":"Ah, scrumptious! Another bowl!","TWN":"真好吃～再來一碗～"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SERVANT_NPC_NANAHARA_NULL","text":{"KOREA":"네. 필요한 반찬이 더 있으시면 말씀만 하세요, 나오님.","JPN":"はい。必要なおかずがございましたらなんなりとお申しつけください、ナオ様。","ENG":"Yes, Miss Nao. Do let us know if there is anything else you need.","TWN":"好的，若是有需要加小菜也儘管說。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오냐~","JPN":"おう～","ENG":"Will do!","TWN":"哇喔～"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송해요, 사나에. 식사를 하시더니 금방 생기를 되찾으셨어요.","JPN":"ごめんなさい、早苗。食事をされてからすぐに元気になられて。","ENG":"I am sorry, Sanae. She got better as soon as she started eating.","TWN":"早苗，抱歉，她吃過飯後就恢復精神了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당연한 것 아니겠냐! 예로부터 밥심으로 낫지 않는 병은 없었다!","JPN":"当たり前じゃ！　昔からご飯の力で治らない病などない！","ENG":"Of course I did! A good meal is a cure to everything!","TWN":"那不是當然的嗎！自古以來沒有什麼病是一頓飯醫不好的！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하하……","JPN":"はは……","ENG":"Ha ha...","TWN":"哈哈……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하야미 가문의 하야미 사나에. 나오님을 이렇게 뵙습니다.","JPN":"速水家の速水早苗。ナオ様にご挨拶申し上げます。","ENG":"Hayami Sanae of the Hayami family greets you, Miss Nao.","TWN":"我是速水家族的速水早苗，見過奈緒大人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오, 눈을 보아하니 네가 하야미 집안의 후손이로구나.","JPN":"おお、目を見れば、お主が速水家の末裔か。","ENG":"Judging from your eyes, you must be a Hayami indeed.","TWN":"喔，看你的眼神確實是速水家族的後裔沒錯。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나나하라류는 잘 계승하고 있겠지?","JPN":"七原流はちゃんと受け継いでいるな？","ENG":"I assume you are still practicing the Nanahara Style?","TWN":"你有好好繼承七原流吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"예. 비록 정식 사범은 아니지만, 나나하라류의 명맥을 지키는 것이 사명이니까요.","JPN":"はい。正式の師範ではございませんが、七原流の命脈を保つことが私の使命でございますゆえ。","ENG":"Yes. I am not an official instructor, but it is it my duty to pass down its heritage.","TWN":"是的，雖然我還不是正式師範，守護七原流的命脈是我的使命。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그런 것 치곤 너……","JPN":"その割にはお主……","ENG":"You say it with a cool face, but...","TWN":"不過你……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"칼을 쥐는 걸 두려워하고 있구나?","JPN":"剣を手に取ることを恐れているのう。","ENG":"You’re afraid of wielding your sword, aren’t you?","TWN":"害怕拿刀嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"예……?","JPN":"はい……？","ENG":"Pardon...?","TWN":"什麼……？你怎麼突然這麼說？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저기…… 두 분은 서로 구면이신 건가요?","JPN":"あの……お二人はお知り合いなのですか？","ENG":"Excuse me, but... do you know each other?","TWN":"請問……你們是舊識嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"아니? 처음 본다만?","JPN":"いや。初めて会ったぞ。","ENG":"Nope. We’ve just met.","TWN":"不是，我是第一次見到她欸？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저도 관리국 데이터베이스를 통해 알고 있을 뿐, 직접 뵙는 것은 처음입니다.","JPN":"私も管理局のデータベースを見て存じ上げているだけで、直接お会いするのは初めてです。","ENG":"I only know of Miss Nao from the Administration database. It is my first time seeing her.","TWN":"我也是透過管理局的資料庫才知道奈緒大人的，見到本人這是第一次。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나오님께선 고르디우스 봉인전대의 1대 전대장이시니까요.","JPN":"ナオ様はゴルディウス封印戦隊の初代戦隊長でございますから。","ENG":"She is the first commander of the Gordias Division, after all.","TWN":"因為她是戈爾迪亞封印戰隊第一戰隊的隊長。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"전대장…… 이라고요?","JPN":"戦隊長……？","ENG":"Commander...?","TWN":"她是……戰隊長嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"몰라 뵈어 죄송합니다.","JPN":"知らぬこととはいえ、大変失礼いたしました。","ENG":"My apologies for not noticing, Miss Nao.","TWN":"我真是有眼不識泰山。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 곳에서 고르디우스의 전대장님을 뵙게 될 줄은……","JPN":"このようなところでゴルディウスの戦隊長様にお会いすることになるとは……","ENG":"I would not have imagined meeting the commander of the Gordias Division at such a place...","TWN":"沒想到會在這裡見到戈爾迪亞戰隊長……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"괜찮다. 모를 만도 하지. 내가 자릴 비운 건 네놈들 증조가 태어나기도 전이니 말이야.","JPN":"気にするな。わからなくて当然じゃ。わしが戦隊を離れたのはお主たちの曾祖父が生まれる前だからのう。","ENG":"It’s fine. Of course you didn’t know. I left my place before your ancestors were even born.","TWN":"沒事，不知道是正常的，畢竟我退休的時候，你們的曾祖輩應該都還沒出生吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇게나 오래 전부터……","JPN":"そんなにも昔から……","ENG":"For all this time...","TWN":"那麼久以前的事嗎……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런데도 무척 젊어 보이시네요.","JPN":"それなのにとてもお若く見えますね。","ENG":"But you still look so young, Miss Nao.","TWN":"但您看起來很年輕呢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그러냐? 나도 너처럼 작은 당주는 처음 본다.","JPN":"そうか？　わしもお主のようなチビ当主は初めて見るわい。","ENG":"Is that so? It’s my first time seeing a Ladychild like you, too.","TWN":"是嗎？我也是第一次看到像你這麼小的堂主呢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"작은…… 당주?","JPN":"チビ……当主？","ENG":"Ladychild...?","TWN":"這麼小的……堂主？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나오님께선 선조신의 직계 후손이십니다. 저희와 달리 사람 피가 거의 섞이지 않으셨지요.","JPN":"ナオ様は冥府の神々の直系子孫でいらっしゃいます。私たちとは違い、人間の血はほとんど混ざっていません。","ENG":"Miss Nao is the direct descendant of the ancestral gods. Unlike us, there is very little human blood that flows in her.","TWN":"奈緒大人是祖先神的直系後裔，她和我們不同，她的血液裡幾乎沒有任何的參雜。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네? 그렇다면 과거엔 나오님 같은 신이 고르디우스 전대에 계셨던 건가요?","JPN":"それでは過去にはナオ様のような神がゴルディウス戦隊にいらっしゃったのですか？","ENG":"Huh? Does that mean that there were gods like you in the Gordias Division?","TWN":"什麼？你的意思是戈爾迪亞戰隊中曾經有像奈緒大人這樣的神嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"착각하고 있구나. 내가 신이었다면 진작에 죽거나 저승에 묻혔겠지.","JPN":"勘違いがあるな。わしが神だったらすでに死んでいるか、冥府に送られておるわ。","ENG":"You’re getting the wrong idea. If I was a god, I would have been long past dead, or buried in the Afterlife.","TWN":"並非如此，我要是神的話，早就已經死掉或是被埋在地獄裡。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"관리국에선 나를 반쪽짜리 환상종이라고 부르긴 했다만……","JPN":"管理局ではわしを不完全な幻想種と呼んではいたんじゃが……","ENG":"The Administration used to call me as a half-Bygone....","TWN":"不過管理局都稱我是半夢幻類……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐, 좋을 대로 부르거라.","JPN":"まあ、好きに呼べ。","ENG":"Whatever. Call me whatever you please.","TWN":"叫什麼都好啦。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 나오님께 한 가지 여쭙고 싶은 것이 있습니다.","JPN":"では、ナオ様に一つお伺いしたいことがあります。","ENG":"I would like to ask you one question, Miss Nao.","TWN":"那，我可以問奈緒大人一個問題嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐냐?","JPN":"何じゃ？","ENG":"And what’s that?","TWN":"什麼問題？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오늘 저희가 만난 것은…… 우연인가요? 아니면 필연인가요?","JPN":"今日私たちが出会ったのは……偶然ですか？　それとも必然ですか？","ENG":"Our encounter today... Was it coincidence? Or fate?","TWN":"我們今日的相遇……是偶然？還是必然呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"우연이 아니라고만 말해두마.","JPN":"偶然ではないと言っておこう。","ENG":"I would say it’s not a coincidence.","TWN":"我只能說不是偶然。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그럼 배도 채웠겠다. 슬슬 용건을 읊어볼까?","JPN":"さあ、腹ごしらえもしたし。そろそろ用件を話してみるかのう。","ENG":"Well, then. Now that I’m full, Let’s get down to business.","TWN":"我看大家應該都吃飽了，那就來談談正事吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너희. <color=#ffd34c>역신베기</color>라고 들어봤느냐?","JPN":"お主たち。<color=#ffd34c>大蛇薙剣</color>という名を聞いたことはあるか？","ENG":"Have any of you heard of <color=#ffd34c>Orochinagi</color>?","TWN":"你們聽過<color=#ffd34c>瘟神斬</color>嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……역신을 막아낼 삼신기 중 유일하게 완성되지 않은 하나라고 배웠습니다.","JPN":"……疫病神の復活を阻止する三神器のうち、唯一完成していない神器であると教わりました。","ENG":"...I heard that it is the only Sacred Treasure that has not been finished out of the Three.","TWN":"……我聽說那是可以阻止瘟神的三神器中，唯一一個沒有完成的神器。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうじゃ。","ENG":"Right.","TWN":"沒錯。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나는 선조들의 유지를 받들어, 그 역신베기를 완성하러 온 거다.","JPN":"わしは先祖たちの遺志を受け、大蛇薙剣を完成させるために来たのじゃ。","ENG":"I came here to complete Orochinagi, upon the legacy of our ancestors.","TWN":"而我承接祖先的遺願，是要來完成瘟神斬的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그러니 하야미 가문의 무사들을 전부 한 자리에 불러 모으거라.","JPN":"ゆえに速水家の武士を全員ここに呼び集めろ。","ENG":"Which is exactly why I need you to gather up the Hayami warriors.","TWN":"所以我要你們立刻召集所有速水家族的武士。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그럴 필요는 없겠습니다.","JPN":"その必要はございません。","ENG":"No need.","TWN":"無須如此大費周章。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하야미 가문 무사는 소인 하나뿐이니까요.","JPN":"速水家の武士は私一人だけですから。","ENG":"I am the sole Hayami warrior that is left.","TWN":"因為速水家族的武士只剩我一人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"한 명……?","JPN":"一人……？","ENG":"Only one...?","TWN":"你一個人……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"아무리 시대가 변했다 한들 하야미 가문에 검을 다루는 인재가 그렇게 없다는 거냐?","JPN":"いくら時代が変わったとて、速水家に剣術に長けた者がそれほどまでにいないのか？","ENG":"I know that times have changed, but surely there should be more talents in the Hayami family?","TWN":"就算時代再怎麼變，速水家族中可以拿劍的人才也不至於這麼少吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"20년 전, 저희 하야미 가문은 모두 전투에 참전했습니다.","JPN":"20年前、私たち速水家は全員戦闘に参戦いたしました。","ENG":"20 years ago, the Hayami family was dispatched to a certain battle.","TWN":"20年前，我們速水家族全員投身戰場。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"소인도 그날 죽음을 각오하였으나, 깨어났을 땐 저 혼자만 살아남았지요.","JPN":"私もあの日死を覚悟していたのですが、目覚めた時には一人だけ生き残っていました。","ENG":"I too was prepared for death, however... when I woke up, I realized I was the sole survivor.","TWN":"那天我也是抱著必死的決心上戰場，但當我醒過來後，卻發現只剩我一人獨活。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"20년 전이라면…….","JPN":"20年前といえば……","ENG":"What you mean by 20 years ago is...","TWN":"20年前嗎……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……쳇, 됐다.","JPN":"……ちっ、もうよい。","ENG":"...Tch. Forget it.","TWN":"……嘖，就這樣吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그럼 검도 휘두르지 못하는 네가 나나하라류를 계승한 유일한 무사라는 거냐?","JPN":"それじゃあ、刀も振るえないお主が七原流を継承した唯一の武士なのか？","ENG":"So you’re saying that you, who can’t even dare to wield your own blade, are the only successor of the Nanahara Style?","TWN":"所以現在不懂拿劍的你是唯一繼承七原流的武士嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"비록 하야미 가문의 사람은 아니지만……","JPN":"速水の者ではありませんが……","ENG":"Despite not being a Hayami...","TWN":"還有一個人，雖然她不是速水家族的人……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저보다 자질이 뛰어난 아이가 하나 있습니다.","JPN":"私より優れた実力を持っている子が一人おります。","ENG":"There is one child who excels at it.","TWN":"但她比我有天賦。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그 자의 공격은 나보다 빠르거나 강하지 않았다.","JPN":"あの者の攻撃は私より早くも、強くもなかった。","ENG":"Her attacks were not faster nor stronger than mine.","TWN":"她的攻擊並沒有比我快，也沒有比我強。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 머릿속으로 아무리 검을 휘두르고 몸을 움직여도,","JPN":"だが、いくら頭の中で刀を振るい身体を動かしてみても、","ENG":"But no matter how much I swiftly move and attack...","TWN":"可是無論我在腦海裡怎麼揮劍，怎麼移動身體，"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"도저히 그 공격을 받아 칠 수가 없어.","JPN":"どうしてもあの攻撃を打ち返すことができない。","ENG":"I couldn’t fight against her.","TWN":"就是無法抵擋她的攻擊。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"마치 내 움직임이 전부 읽히고 있는 것처럼……","JPN":"まるで私の動きをすべて読まれているかのように……","ENG":"It was as if she already knew my next move...","TWN":"彷彿她能夠看穿我一切的行動……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"틀렸어.","JPN":"駄目だ。","ENG":"No.","TWN":"不行！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"한심한 것. 이런 실력으로 어떻게 당주님을 지키겠단 말이냐?","JPN":"情けない。こんな実力でどうやって当主を守るというんだ。","ENG":"How pathetic am I? How could I ever protect Lady Nanahara when I am so weak?","TWN":"沒出息的東西！這樣是要怎麼保護堂主？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그때 도움을 받지 못했더라면 나는 지금쯤……","JPN":"あの時助けてもらわなかったら今頃私は……","ENG":"If it had not been for Miss Nao, I would have been–","TWN":"那時候要是沒人出手相救，恐怕我現在已經……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그런 부러진 검으로 검술 연습을 하고 있는 게냐?","JPN":"そのような折れた刀で剣術の修練をしておるのか？","ENG":"You’re training with a broken sword?","TWN":"你用那把斷劍在練習劍法嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님……? 이런 곳엔 어쩐 일이십니까?","JPN":"ナオ様……？　なにゆえこのようなところに？","ENG":"Miss Nao...? What brings you here?","TWN":"奈緒……？你怎麼會在這裡？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내가 그거 고쳐줄까?","JPN":"それ、わしが直してやろうか。","ENG":"You know, I could fix that for you.","TWN":"要我幫你修嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아닙니다. 은인 분에게 어찌 그런 수고를……","JPN":"いいえ。恩人にそのような手間をおかけするわけには……","ENG":"No, but thank you. I could never ask for more from my savior–","TWN":"不行，怎麼可以麻煩恩人……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나나하라의 검들은 모두 나와 제자들이 만든 것이다. 고치는 것쯤은 내게 식은 죽먹기지.","JPN":"七原の刀剣はすべてわしと弟子たちで作ったものじゃ。直すことくらい朝飯前じゃ。","ENG":"All swords of the Nanahara family were made by me and my apprentices. Fixing one is nothing.","TWN":"七原的劍都是我和徒弟做的，修好它對我來說根本不費吹灰之力。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예……? 그게 정말입니까?","JPN":"なんと……？　それは本当ですか？","ENG":"Huh...? Is that really the truth?","TWN":"什麼……？真的嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래, 그 검의 슴베 쪽을 확인해봐라.","JPN":"おう、その刀のなかごの部分を確認してみろ。","ENG":"Of course. Check the tang of your sword, will you?","TWN":"當然，你看看劍上面，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내 제자들이 만든 검에는 전부 꽃이름을 붙여줬거든.","JPN":"わしの弟子たちが作った刀剣にはすべて花の名前をつけてある。","ENG":"All of the swords that my apprentices made were named after flowers.","TWN":"我徒弟做的劍上都會刻上花的名字。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……정말이군요. 수선이라고 새겨져 있습니다.","JPN":"……本当ですね。水仙と刻まれております。","ENG":"...You are right. I see \\"Narcissus\\" engraved on it.","TWN":"……是真的，上面刻著水仙。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"호오, 제법 좋은 검을 쓰고 있었구나. 수선은 내 수제자가 만든 것이지.","JPN":"ほう、なかなか良いものを使っておるな。水仙はわしの一番弟子が作ったものじゃ。","ENG":"Oh? That’s a fine one you’ve got. Narcissus was made by my best pupil.","TWN":"喔呵，你拿到一把好劍呢，水仙是我的大徒弟做的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"녀석에게 쓰고 싶은 글귀가 있으면 남겨두라고 했는데, 혹시 뭐라고 적혀있느냐?","JPN":"やつに刻みたい言葉があれば残しておけと言ったのじゃが、何と書いてあるのかのう？","ENG":"I told her to engrave whatever text she wished to leave behind. What does it say?","TWN":"我跟他說想說什麼都可以刻在劍上，上面有寫什麼話嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>땅딸보 꼰대 스승 언젠가 짓밟고 만다</color>……","JPN":"<color=#ffd34c>チビくそババァの師匠、いつか踏みつけてやる</color>……","ENG":"<color=#ffd34c>I swear I’m going to crush my midget of a master someday</color>...","TWN":"<color=#ffd34c>矮冬瓜老太婆師父，總有一天我會贏過你</color>……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"라고 되어있습니다만.","JPN":"と、刻まれていますが。","ENG":"That is what it says.","TWN":"上面是這樣寫的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……으하하! 스승을 뛰어넘고자 하는 제자의 훌륭한 자세로군!","JPN":"……ははは！　師匠を超えようとする弟子の立派な心がけじゃ！","ENG":"...Ha ha ha! That’s the spirit! Surpass your master!","TWN":"……哈哈哈！原來是想要超越師父嗎？非常棒的宣告！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐, 그 소원은 결국 이뤄지지 못했지만 말이지.","JPN":"まあ、その願いは結局叶わなかったがな。","ENG":"Too bad the wish never came true, though.","TWN":"不過這句話終究沒有成真。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내가 그 검을 고치는 동안 너는 이걸로 연습이나 해라.","JPN":"わしがその刀を直す間、お主はこれで練習でもしていろ。","ENG":"Here, practice with this while I fix your sword.","TWN":"在我替你修劍的時候，你先用這把劍練習吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이건…… 특이한 색을 가진 검이로군요.","JPN":"これは……独特な色をした刀ですね。","ENG":"This... has an interesting sheen to it.","TWN":"這把劍……顏色好特別。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"한 번 휘둘러보겠느냐?","JPN":"一度振るってみないか？","ENG":"Want to try it out?","TWN":"你要試著揮揮看嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……承知しました。","ENG":"...Very well.","TWN":"……好的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"큭?! 무거워?","JPN":"くっ！？　重い？","ENG":"Kgh?! How is it so heavy?","TWN":"唔？！好沉？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"흐음…… 역시 휘두르는 것까지는 못하는 건가?","JPN":"ふむ……やはり振るうことまでは無理かのう。","ENG":"Hmm... I guess using it properly is out of the question.","TWN":"嗯……揮不動嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님, 이 검은 대체……?","JPN":"ナオ様、この刀はいったい……？","ENG":"Miss Nao, what is this sword...?","TWN":"奈緒，這把劍究竟是……？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"평범한 인간은 그걸 손에 쥐는 것만으로도 힘겨워하지.","JPN":"普通の人間ならばそれを手に持っているだけでもつらい。","ENG":"Normal humans can’t even bear holding it.","TWN":"一般人光是要拿起這把劍都很費力，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그걸 가볍게 들 수 있다는 건, 네가 나나하라류의 무사로서 최소한의 자격은 갖추었다는 뜻이다.","JPN":"それをひょいと持ち上げられるということは、お主が七原流の武士として最低限の資格は持っているという意味じゃ。","ENG":"The fact that you’re able to hold it around freely means that you passed the minimum requirements of becoming a Nanahara Style warrior.","TWN":"如果可以輕鬆拿起這把劍，就表示你有成為七原流武士的最基本資格。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님께서 나나하라류를 어찌 아시는지요?","JPN":"ナオ様はどうして七原流をご存じなのですか？","ENG":"How are you aware of Nanahara Style, Miss Nao?","TWN":"你怎麼會知道七原流？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그야 내가 고르디우스의 대장 노릇을 맡을 적부터 그 검술을 배운 녀석들만 데리고 다녔으니 그렇지.","JPN":"そりゃあ、わしがゴルディウスの隊長をやっていた頃からその剣術を身につけたやつらだけを連れていたからな。","ENG":"That’s because I used to hang out with a bunch of Nanahara warriors ever since I was Commander at the Gordias Division.","TWN":"因為我擔任戈爾迪亞的戰隊長時，我帶的傢伙都學過這套劍法。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예? 하지만 고르디우스는 초대전대장이 사라진 뒤로 계속 공석이었다고 들었습니다만……?","JPN":"え？　ですがゴルディウスは初代戦隊長が行方不明になった後からずっと空席だと聞きましたが……？","ENG":"Huh? But I heard that the commander’s seat remained empty after the first one disappeared...","TWN":"什麼？可是我聽說戈爾迪亞自從初代戰隊長消失後，就一直是從缺的狀態……？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오냐.","JPN":"おう。","ENG":"Correct.","TWN":"對。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그런 줄도 모르고 감히 존함을 읊는 무례를 범했군요.","JPN":"知らぬこととはいえ、ご尊名でお呼びした無礼をお許しください。","ENG":"I apologize for my discourtesy.","TWN":"我竟敢直呼您的名諱，請原諒我的失禮。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"전대장 어르신…… 이라고 불러드리면 되겠습니까?","JPN":"戦隊長様……とお呼びしたらいいのでしょうか。","ENG":"Should I call you... Commander?","TWN":"戰隊長大人……這樣稱呼您可以嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"흥, 이제 와서 늙은이 취급할 셈이냐? 계속 나오님이라고 불러라.","JPN":"ふん、今更年寄り扱いするつもりか？　そのままナオ様と呼べ。","ENG":"Tsk, You sound like you’re caught up on my age, child. Call me Nao.","TWN":"哼，你現在是想把我叫老嗎？一樣叫我奈緒大人就好。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……承知いたしました。","ENG":"...Yes, Miss Nao.","TWN":"……是的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그건 그렇고, 네 녀석은 역신베기에 대해 들어봤느냐?","JPN":"それはそうと、お主は大蛇薙剣について知っているか？","ENG":"That aside, are you familiar with Orochinagi?","TWN":"先不說這個，你聽過瘟神斬嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아는 것은 많지 않으나…… 역신을 벨 수 있는 검이라고 들었습니다.","JPN":"そう詳しくはありませんが……疫病神を斬ることができる剣だと聞きました。","ENG":"I don’t know a lot about it... but I heard that it is the sword that can slay the Plague God.","TWN":"我知道的不多……只知道是可以斬殺瘟神的劍。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうじゃ。","ENG":"Right.","TWN":"沒錯。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그리고 그 검이 바로 역신베기의 초석인 명부검이다.","JPN":"そしてお主の持つその刀が大蛇薙剣の基礎となる冥府剣じゃ。","ENG":"The sword you are holding right now is the foundation, the Nether God’s Sword.","TWN":"而你手上那把劍叫作冥府劍，它是完成瘟神斬不可或缺的材料。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"옛 명부신께서 휘두르던 검을 내 선조들이 복원한 것이지.","JPN":"昔、冥府の神が持っていた剣を、わしの先祖が復元したのだ。","ENG":"It belonged to the Nether God, now restored by my ancestors.","TWN":"它原是冥府神使用過的劍，後來我的祖先將其復原。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예……? 그럼 이것을 휘두를 수만 있으면 역신을 막을 수 있는 겁니까?","JPN":"はい……？　ではこれを振るうことができれば、疫病神の復活を阻止することができるのですか？","ENG":"Huh...? Does that mean that we can stop the Plague God, once I am able to use this?","TWN":"什麼……？那意思就是，只要能揮動這把劍，就可以抵擋瘟神嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"순진하구나. 그게 말처럼 쉬우면 누가 역신을 두려워하겠냐?","JPN":"ウブじゃのう。そんなに容易いことなら疫病神を恐れる者はおるまい。","ENG":"Naive much, are you? It’s easier said than done.","TWN":"真是天真，要是有這麼容易，還有誰會怕瘟神？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇…… 습니까?","JPN":"そう……ですか？","ENG":"O-oh...","TWN":"是……嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"역신베기를 완성하기 위해서는 그 명부검에 어울리는 나나하라 혈통의 영혼이 필요하다.","JPN":"大蛇薙剣を完成させるためには、冥府剣に相応しい七原の血統を持つ魂が必要なんじゃ。","ENG":"To complete Orochinagi, we need the soul of a rightful Nanahara descendant.","TWN":"完成瘟神斬還需要是七原血統的靈魂。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"허나 아직도 그 조건에 맞는 영혼은 나타난 적이 없다.","JPN":"だが、いまだにその条件に合う魂は現れておらん。","ENG":"However, there were none so far.","TWN":"不過，到目前為止，還沒有符合條件的靈魂出現過。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 오늘 이곳에 오신 이유 또한……","JPN":"それでは、今日ここに来られた理由も……","ENG":"That means... the reason why you are here is...","TWN":"所以您今日造訪的目的就是……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래, 이 명부검을 역신베기로 완성하기 위해서지.","JPN":"うむ。この冥府剣を大蛇薙剣に仕上げるためじゃ。","ENG":"Yes. It is to change the Nether God’s Sword into Orochinagi, its ultimate form.","TWN":"沒錯，就是要完成拿冥府劍完成瘟神斬。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저에게 이 검을 쥐어 주신 것에는 그럴 만한 이유가 있을 터……","JPN":"私にこの剣を握らせたのには相応の理由があるはず……","ENG":"There must be a reason why you have handed me this sword...","TWN":"那您把這把劍交給我的原因是……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"혹 제가 그에 걸맞은 조건을 가진 사람입니까?","JPN":"もしや私が冥府剣に相応しい条件を持っている者なのでしょうか？","ENG":"Am I the rightful one?","TWN":"難道我是符合資格的人選嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"흐흥, 반은 맞고 반은 틀렸다.","JPN":"ふふん、半分当たっているが半分は外れているのう。","ENG":"Hmm. Kind of, but not quite.","TWN":"嗯哼，你只說對一半。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"명부신께서 말씀하시길……","JPN":"冥府の神は……","ENG":"As the Nether God once said...","TWN":"冥府神說……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>역신베기는 두려워 할 죽음이 없는 무사가 자신의 목숨을 바쳐 완성되리라.</color>","JPN":"<color=#ffd34c>大蛇薙剣は恐れるべき死のない武士が自らの命を捧げることにより完成するであろう。</color>","ENG":"<color=#ffd34c>Completed shall Orochinagi be, with the life of a warrior unafraid of all death.</color>","TWN":"<color=#ffd34c>瘟神斬必須由無懼死亡的武士獻上自己的性命才能完成。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……라고 하셨다.","JPN":"……とおっしゃった。","ENG":"...And so on.","TWN":"……他是這麼說的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이곳에 오기 전까지 어느 정도 기대를 갖고 있던 건 사실이다만……","JPN":"いくばくかの期待を持ってここへやって来はしたが……","ENG":"I admit, I did have high hopes before arriving here...","TWN":"我今日確實是帶著某種程度的期待而來……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너에겐 어울리지 않는 역할이다.","JPN":"お主には似合わぬ役割じゃ。","ENG":"But it is not your role.","TWN":"不過你不是對的人。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저는 당주님을 지킬 수만 있다면, 죽음 같은 건 두렵지 않습니다.","JPN":"私は当主を守れるのなら、死など怖くありません。","ENG":"As long as I can protect Lady Nanahara, death is meaningless to me.","TWN":"只要能保護堂主，要我犧牲性命我也不怕。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네가 그 가면 쓴 계집과 싸울 때 이미 확신했다.","JPN":"お主があの仮面の娘と戦った時に確信したのじゃ。","ENG":"It was apparent already when you were fighting that masked girl.","TWN":"在你和那個戴面具的丫頭對打時我就知道，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"넌 명부신께서 예견한 무사가 아니야.","JPN":"お主は冥府の神が予言した武士ではない。","ENG":"You are not the warrior that the Nether God predicted.","TWN":"你不是冥府神預言的武士。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇게 말씀하시는 이유는……. 제가 그자에게 패배했기 때문입니까?","JPN":"そうおっしゃる理由は……私があの者に負けたからですか？","ENG":"Is it... because I lost against her?","TWN":"您之所以會這麼說……是因為我打輸她嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"두려워 할 죽음이 없다는 건 비단 자기 목숨만을 두고 하는 얘기가 아니다.","JPN":"恐れるべき死がないというのは、己の命のみを指して言っているのではないのじゃ。","ENG":"To be unafraid of death goes beyond your own life.","TWN":"所謂無懼死亡，並不單指犧牲自己的性命。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너도 네 목숨만큼 중히 여기는 것이 하나쯤은 있지 않느냐?","JPN":"お主とてその命と同じくらい大切にしているものが一つくらいはあるじゃろう？","ENG":"Don’t you have something dear to you, enough to sacrifice your own life for?","TWN":"你的生命中有一個如自己性命般重要的人吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"목숨만큼…… 중요한 것?","JPN":"命と同じくらい……大切なもの？","ENG":"Something dear...?","TWN":"如自己性命般……重要的人？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그런 고로 너에게는 아직 무리다.","JPN":"そういうわけで、お主にはまだ無理じゃ。","ENG":"That’s why this role is not your place.","TWN":"因此你不不符合條件。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그러니 난 이만 다른 마땅한 주인이 있는지 찾으러 가봐야겠구나.","JPN":"わしは他に適当な者がいないか探しに行くことにするかのう。","ENG":"I must get going now. I need to find another worthy candidate.","TWN":"我現在要去找找有沒有其他合適的人選。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……아.","JPN":"……あ。","ENG":"...Oh.","TWN":"……那個，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이 명부검은 가져가지 않으시는 겁니까?","JPN":"この冥府剣は持っていかれないのですか？","ENG":"Are you not going to take this sword back?","TWN":"這把冥府劍您沒有要帶走嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"들고 다니기 귀찮다. 네 녀석이 잠시 맡아 두거라.","JPN":"持ち歩くのが面倒なんじゃ。お主がしばし預かっておけ。","ENG":"It’s a hassle to carry it around all the time. You take care of it for the mean time.","TWN":"我帶著它礙事，就先交給你保管吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 검은 베지 못할 뿐, 쓰는 데엔 문제없을 거다.","JPN":"その刀は斬ることができないだけで、使うには問題なかろう。","ENG":"You won’t have any problems using it, apart from slashing.","TWN":"它只是沒辦法斬殺而已，起碼還是堪用的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"말인 즉, 공격을 막으려다 부러질 일은 없다는 게지.","JPN":"つまり、攻撃を止めようとして折れることはないということじゃ。","ENG":"In other words, it will never break trying to block something.","TWN":"意思就是，在抵擋別人的攻擊時也不會斷掉。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};